@@ -1223,3 +1223,323 @@ select:focus-visible {
 .raptorq-scope ::selection {
   background: rgba(34, 211, 238, 0.2);
 }
+
+/*
+  ========================================
+  OVERPROMPTING ARTICLE - SCOPED STYLES
+  All styles scoped under .overprompting-scope
+  to avoid leaking to the rest of the site.
+  ========================================
+*/
+
+.overprompting-scope {
+  --op-bg: #020204;
+  --op-text: #f8fafc;
+  --op-muted: #64748b;
+  --op-amber: #f59e0b;
+  --op-orange: #f97316;
+  --op-rose: #f43f5e;
+}
+
+/* Display title - fluid clamp sizing */
+.overprompting-scope .op-display-title {
+  font-family: var(--font-bricolage), system-ui, sans-serif;
+  font-size: clamp(3rem, 10vw, 7.5rem);
+  line-height: 0.85;
+  letter-spacing: -0.06em;
+  font-weight: 900;
+}
+
+/* Section titles with amber bar pseudo-element */
+.overprompting-scope .op-section-title {
+  font-family: var(--font-bricolage), system-ui, sans-serif;
+  font-size: clamp(2rem, 5vw, 3.5rem);
+  letter-spacing: -0.05em;
+  font-weight: 900;
+  display: flex;
+  align-items: center;
+  gap: 1rem;
+}
+
+.overprompting-scope .op-section-title::before {
+  content: "";
+  width: 0.375rem;
+  height: 2rem;
+  background-color: var(--op-amber);
+  border-radius: 9999px;
+  flex-shrink: 0;
+}
+
+/* Drop cap for intro paragraph */
+.overprompting-scope .op-drop-cap::first-letter {
+  font-size: 4.5rem;
+  font-weight: 900;
+  color: var(--op-amber);
+  float: left;
+  margin-right: 0.75rem;
+  margin-top: 0.25rem;
+  line-height: 0.8;
+  font-family: var(--font-bricolage), system-ui, sans-serif;
+}
+
+/* Callout blockquote */
+.overprompting-scope .op-callout {
+  border-left: 4px solid rgba(245, 158, 11, 0.5);
+  padding-left: 2rem;
+  padding-top: 1rem;
+  padding-bottom: 1rem;
+  margin-top: 3rem;
+  margin-bottom: 3rem;
+  background: linear-gradient(90deg, rgba(245, 158, 11, 0.04) 0%, transparent 100%);
+  font-size: 1.375rem;
+  line-height: 1.75;
+  font-style: italic;
+  color: #cbd5e1;
+}
+
+/* Viz containers and headers */
+.overprompting-scope .op-viz-container {
+  width: 100%;
+  margin-top: 3rem;
+  margin-bottom: 3rem;
+  border-radius: 1.5rem;
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  background: rgba(255, 255, 255, 0.02);
+  overflow: hidden;
+  backdrop-filter: blur(12px);
+}
+
+.overprompting-scope .op-viz-header {
+  padding: 1rem 1.5rem;
+  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
+  display: flex;
+  flex-direction: column;
+  gap: 0.5rem;
+  background: rgba(255, 255, 255, 0.02);
+}
+
+@media (min-width: 768px) {
+  .overprompting-scope .op-viz-header {
+    padding: 1.5rem 2rem;
+  }
+}
+
+/* Buttons */
+.overprompting-scope .op-btn-action {
+  padding: 0.625rem 1.25rem;
+  background: var(--op-amber);
+  color: black;
+  font-weight: 900;
+  font-size: 10px;
+  letter-spacing: 0.15em;
+  border-radius: 9999px;
+  border: none;
+  cursor: pointer;
+  transition: all 0.15s ease-out;
+  text-transform: uppercase;
+}
+
+.overprompting-scope .op-btn-action:hover:not(:disabled) {
+  background: #fbbf24;
+  transform: scale(1.05);
+}
+
+.overprompting-scope .op-btn-action:active:not(:disabled) {
+  transform: scale(0.95);
+}
+
+.overprompting-scope .op-btn-action:disabled {
+  opacity: 0.4;
+  cursor: not-allowed;
+}
+
+.overprompting-scope .op-btn-secondary {
+  padding: 0.625rem 1.25rem;
+  background: transparent;
+  border: 1px solid rgba(255, 255, 255, 0.2);
+  color: white;
+  font-weight: 900;
+  font-size: 10px;
+  letter-spacing: 0.15em;
+  border-radius: 9999px;
+  cursor: pointer;
+  transition: all 0.15s ease-out;
+  text-transform: uppercase;
+}
+
+.overprompting-scope .op-btn-secondary:hover:not(:disabled) {
+  border-color: white;
+  background: rgba(255, 255, 255, 0.05);
+}
+
+.overprompting-scope .op-btn-secondary:disabled {
+  opacity: 0.4;
+  cursor: not-allowed;
+}
+
+@media (min-width: 768px) {
+  .overprompting-scope .op-btn-action,
+  .overprompting-scope .op-btn-secondary {
+    padding: 0.75rem 2rem;
+    font-size: 11px;
+    letter-spacing: 0.2em;
+  }
+}
+
+/* Insight card */
+.overprompting-scope .op-insight-card {
+  margin-top: 3rem;
+  margin-bottom: 3rem;
+  padding: 2rem;
+  border-radius: 1rem;
+  border: 1px solid rgba(255, 255, 255, 0.1);
+  background: linear-gradient(135deg, rgba(245, 158, 11, 0.06) 0%, rgba(244, 63, 94, 0.04) 100%);
+  backdrop-filter: blur(12px);
+}
+
+@media (min-width: 768px) {
+  .overprompting-scope .op-insight-card {
+    padding: 2.5rem;
+    border-radius: 1.5rem;
+  }
+}
+
+/* Scroll progress bar */
+.overprompting-scope .op-progress-bar {
+  position: fixed;
+  top: 0;
+  left: 0;
+  height: 3px;
+  width: 100%;
+  transform-origin: left;
+  background: linear-gradient(90deg, #f59e0b, #f97316, #f43f5e);
+  z-index: 9999;
+  pointer-events: none;
+}
+
+/* Editorial paragraph styling */
+.overprompting-scope.op-body p:not(.text-sm):not(.text-base):not(.text-xl) {
+  font-size: 1.625rem;
+  line-height: 1.85;
+  color: #f1f5f9;
+  margin-bottom: 2.25rem;
+  margin-top: 0;
+  font-family: var(--font-crimson), Georgia, serif;
+  font-variant-numeric: oldstyle-nums;
+  hanging-punctuation: first;
+}
+
+.overprompting-scope.op-body p:not(.text-sm):not(.text-base):not(.text-xl) + p:not(.text-sm):not(.text-base):not(.text-xl) {
+  margin-top: 2.25rem;
+}
+
+.overprompting-scope.op-body strong {
+  color: white;
+  font-weight: 900;
+  letter-spacing: -0.01em;
+}
+
+.overprompting-scope.op-body code {
+  font-family: var(--font-jetbrains), ui-monospace, monospace;
+  color: #f59e0b;
+  background: rgba(245, 158, 11, 0.12);
+  padding: 0.125rem 0.375rem;
+  border-radius: 0.25rem;
+  font-size: 0.875em;
+}
+
+/* Card text */
+.overprompting-scope .op-insight-card p {
+  color: #cbd5e1;
+  line-height: 1.8;
+  font-size: 1.25rem;
+  margin-bottom: 1.5rem;
+}
+
+.overprompting-scope .op-insight-card p:last-child {
+  margin-bottom: 0;
+}
+
+/* Mobile full-bleed visualizations */
+@media (max-width: 640px) {
+  .overprompting-scope .op-viz-container {
+    margin-left: -1rem;
+    margin-right: -1rem;
+    border-radius: 0;
+    border-left: none;
+    border-right: none;
+  }
+
+  .overprompting-scope .op-drop-cap::first-letter {
+    font-size: 3.25rem;
+    margin-right: 0.5rem;
+  }
+
+  .overprompting-scope .op-callout {
+    font-size: 1.15rem;
+    padding-left: 1.25rem;
+    margin-top: 1.5rem;
+    margin-bottom: 1.5rem;
+  }
+
+  .overprompting-scope.op-body p:not(.text-sm):not(.text-base):not(.text-xl) {
+    font-size: 1.375rem;
+    line-height: 1.85;
+    margin-bottom: 3rem;
+  }
+
+  .overprompting-scope .op-insight-card p {
+    font-size: 1.1875rem;
+    line-height: 1.75;
+  }
+
+  .overprompting-scope .op-progress-bar {
+    top: env(safe-area-inset-top, 0px);
+  }
+}
+
+/* Section reveal on scroll */
+.overprompting-scope .op-fade-section {
+  opacity: 0;
+  transform: translateY(32px);
+  transition:
+    opacity 0.7s cubic-bezier(0.16, 1, 0.3, 1),
+    transform 0.7s cubic-bezier(0.16, 1, 0.3, 1);
+}
+
+.overprompting-scope .op-fade-section.op-visible {
+  opacity: 1;
+  transform: translateY(0);
+}
+
+@media (prefers-reduced-motion: reduce) {
+  .overprompting-scope .op-fade-section {
+    opacity: 1;
+    transform: none;
+    transition: none;
+  }
+}
+
+/* Button focus-visible */
+.overprompting-scope .op-btn-action:focus-visible,
+.overprompting-scope .op-btn-secondary:focus-visible {
+  outline: 2px solid var(--op-amber);
+  outline-offset: 2px;
+}
+
+/* Text selection */
+.overprompting-scope ::selection {
+  background: rgba(245, 158, 11, 0.2);
+}
+
+/* Keyframe for constraint list fade-in */
+@keyframes opFadeIn {
+  from {
+    opacity: 0;
+    transform: translateX(-8px);
+  }
+  to {
+    opacity: 1;
+    transform: translateX(0);
+  }
+}
